5	
6	//! Kernel launch infrastructure with rust-analyzer type hint support.
7	//!
8	//! This module provides traits and helpers for launching CUDA kernels with
9	//! full IDE type checking. The key insight is separating concerns:
10	//!
11	//! - **Macro** (`cuda_launch!`): Captures kernel identifier → PTX name string,
12	//!   marshals arguments into a `Vec<*mut c_void>`, and calls
13	//!   `cuda_core::launch_kernel` directly. The macro is caller-unsafe: it
14	//!   cannot check argument count or types against the kernel, so every use
15	//!   must sit inside an `unsafe { }` block. Prefer `#[cuda_module]` for
16	//!   kernels embedded in your own crate.
17	//! - **Traits** (`CudaKernel`, `GenericCudaKernel`): Provide PTX entry-point
18	//!   names for rust-analyzer and compile-time validation.
19	
20	use std::ffi::c_void;
21	#[cfg(feature = "async")]
22	use std::sync::Arc;
23	
24	// =============================================================================
25	// Core Traits
26	// =============================================================================
27	
28	/// Trait implemented by kernel functions.
29	///
30	/// This trait is automatically generated by the `#[kernel]` attribute macro.
31	/// It provides the PTX entry point name for runtime kernel lookup.
32	///
33	/// # Example
34	///
35	/// When you write:
36	/// ```ignore
37	/// #[kernel]
38	/// pub fn vecadd(a: &[f32], b: &[f32], mut c: DisjointSlice<f32>) { ... }
39	/// ```
40	///
41	/// The macro generates (on host side only):
42	/// ```ignore
43	/// pub struct __vecadd_CudaKernel;
44	/// impl CudaKernel for __vecadd_CudaKernel {
45	///     const PTX_NAME: &'static str = "vecadd";  // Original function name
46	/// }
47	/// ```
48	///
49	/// Note: the function is renamed internally to `cuda_oxide_kernel_<hash>_vecadd`
50	/// for detection by the compiler backend (the prefix is owned by the
51	/// workspace-internal `reserved-oxide-symbols` crate), but the PTX entry point
52	/// uses the original name.
53	pub trait CudaKernel {
54	    /// The PTX entry point name (e.g., "vecadd" - the original function name)
55	    const PTX_NAME: &'static str;
56	}
57	
58	/// Trait for generic kernel functions.
59	///
60	/// Unlike `CudaKernel`, this trait provides a function to get the PTX name
61	/// because generic kernels have different PTX names for each type/const
62	/// specialization.
63	///
64	/// # Example
65	///
66	/// For a generic kernel:
67	/// ```ignore
68	/// #[kernel]
69	/// pub fn scale<T: Copy + Mul<Output = T>>(factor: T, input: &[T], mut out: DisjointSlice<T>) { ... }
70	/// ```
71	///
72	/// Application code asks the generated helper for a concrete specialization:
73	/// ```ignore
74	/// let name = scale_ptx_name::<f32>();
75	/// // "scale_TID_<32 lowercase hex characters>"
76	/// ```
77	///
78	/// `#[kernel]` implements this trait on an internal marker type and exposes
79	/// the helper above. Application code should use the helper rather than name
80	/// that marker directly. The helper also retains the requested specialization
81	/// in device output before it returns the lookup name.
82	///
83	/// # PTX Naming Scheme
84	///
85	/// Generic kernels are named `<base>_TID_<hex32>`, where `<hex32>` hashes the
86	/// concrete generated kernel function-item type. That `FnDef` contains the
87	/// function identity plus every ordered type and const argument. The host uses
88	/// `cuda_host::type_id_u128_of_val(&kernel_entry::<T, N>)`; the backend hashes
89	/// `Instance::ty` for the same entry. Both use rustc's region-erasing stable
90	/// type hash, so lifetimes do not create spurious PTX variants and the name
91	/// remains fixed-length regardless of generic arity.
92	///
93	/// The bound on `ptx_name` is intentionally just whatever the kernel
94	/// itself declared — typically `Copy` on the value-passed generics. No
95	/// `'static` is added: the helper `cuda_host::type_id_u128` uses
96	/// `core::intrinsics::type_id`, which is bound `T: ?Sized` rather than
97	/// `T: 'static`, so closures that borrow non-`'static` data still go
98	/// through the typed launch path (just like they did under the legacy
99	/// `type_name`-based scheme).
100	pub trait GenericCudaKernel {
101	    /// Get the PTX entry point name for this specific instantiation.
102	    ///
103	    /// Unlike `CudaKernel::PTX_NAME`, this is a function because the name
104	    /// depends on the concrete type and const specialization.
105	    fn ptx_name() -> &'static str;
106	}
107	
108	// =============================================================================
109	// Typed Kernel Arguments
110	// =============================================================================
111	
112	/// Marker trait for values that may be passed to a CUDA kernel by value.
113	///
114	/// `#[cuda_module]` uses this trait for scalar kernel parameters. Any `Copy`
115	/// value can be used here because cuda-oxide compiles the host and device
116	/// instantiations from the same Rust type. Prefer `#[repr(C)]` for structs that
117	/// must also interoperate with CUDA C/C++ code.
118	pub trait KernelScalar: Copy {}
119	
120	impl<T: Copy> KernelScalar for T {}
121	
122	/// Pushes a by-value scalar kernel argument into a CUDA driver argument list.
123	///
124	/// The pointed-to value must remain alive until the launch submission call has
125	/// returned. The generated `#[cuda_module]` launch methods create stack locals
126	/// for this purpose before calling this helper.
127	///
128	/// # Zero-sized values
129	///
130	/// `T` is allowed to be zero-sized (e.g. a closure with no captures, a unit
131	/// struct). When `size_of::<T>() == 0` the backend drops the corresponding
132	/// `.param` entirely from the kernel's PTX entry point — the CUDA driver
133	/// reads no bytes for it — so we must also skip the host push to keep the
134	/// driver's `kernelParams[]` indices aligned with the kernel's declared
135	/// parameters. The check is a `const`-fold for monomorphized types and
136	/// disappears in release builds for non-ZSTs.
137	#[inline]
138	#[doc(hidden)]
139	pub fn push_kernel_scalar<T: KernelScalar>(args: &mut Vec<*mut c_void>, value: &mut T) {
140	    if std::mem::size_of::<T>() == 0 {
141	        return;
142	    }
143	    args.push(value as *mut T as *mut c_void);
144	}
145	
146	/// Returns the `(device pointer, element count)` pair used for read-only slice
147	/// parameters such as `&[T]`.
148	#[inline]
149	#[doc(hidden)]
150	pub fn read_only_device_buffer_arg<T>(
151	    buffer: &cuda_core::DeviceBuffer<T>,
152	) -> (cuda_core::sys::CUdeviceptr, u64) {
153	    (buffer.cu_deviceptr(), buffer.len() as u64)
154	}
155	
156	/// Returns the `(device pointer, element count)` pair used for writable slice
157	/// parameters such as `&mut [T]` and `DisjointSlice<T>`.
158	#[inline]
159	#[doc(hidden)]
160	pub fn writable_device_buffer_arg<T>(
161	    buffer: &mut cuda_core::DeviceBuffer<T>,
162	) -> (cuda_core::sys::CUdeviceptr, u64) {
163	    (buffer.cu_deviceptr(), buffer.len() as u64)
164	}
165	
166	/// Pushes a device slice argument pair into a CUDA driver argument list.
167	///
168	/// cuda-oxide device slices lower to two kernel parameters: `CUdeviceptr` and
169	/// `u64` element count. Keeping that encoding here makes the generated
170	/// `#[cuda_module]` methods target a stable helper instead of open-coding the
171	/// ABI in every expansion.
172	#[inline]
173	#[doc(hidden)]
174	pub fn push_kernel_device_slice(
175	    args: &mut Vec<*mut c_void>,
176	    ptr: &mut cuda_core::sys::CUdeviceptr,
177	    len: &mut u64,
178	) {
179	    args.push(ptr as *mut cuda_core::sys::CUdeviceptr as *mut c_void);
180	    args.push(len as *mut u64 as *mut c_void);
181	}
182	
183	// =============================================================================
184	// Typed Async Kernel Arguments
185	// =============================================================================
186	
187	/// A typed device allocation that can be passed to an async kernel launch as a
188	/// read-only device slice.
189	#[cfg(feature = "async")]
190	pub trait KernelSliceArg {
191	    /// Element type stored in the allocation.
192	    type Elem;
193	
194	    /// Returns the raw CUDA device pointer for the allocation.
195	    fn cu_deviceptr(&self) -> cuda_core::sys::CUdeviceptr;
196	
197	    /// Returns the number of `T` elements in the allocation.
198	    fn len(&self) -> usize;
199	
200	    /// Returns true when the allocation has zero elements.
201	    fn is_empty(&self) -> bool {
202	        self.len() == 0
203	    }
204	}
205	
206	/// A typed device allocation that can be passed to an async kernel launch as a
207	/// writable device slice.
208	#[cfg(feature = "async")]
209	pub trait KernelSliceArgMut: KernelSliceArg {}
210	
211	#[cfg(feature = "async")]
212	impl<T> KernelSliceArg for cuda_core::DeviceBuffer<T> {
213	    type Elem = T;
214	
215	    fn cu_deviceptr(&self) -> cuda_core::sys::CUdeviceptr {
216	        self.cu_deviceptr()
217	    }
218	
219	    fn len(&self) -> usize {
220	        self.len()
221	    }
222	}
223	
224	#[cfg(feature = "async")]
225	impl<T> KernelSliceArgMut for cuda_core::DeviceBuffer<T> {}
226	
227	#[cfg(feature = "async")]
228	impl<T: Send> KernelSliceArg for cuda_async::device_box::DeviceBox<[T]> {
229	    type Elem = T;
230	
231	    fn cu_deviceptr(&self) -> cuda_core::sys::CUdeviceptr {
232	        self.cu_deviceptr()
233	    }
234	
235	    fn len(&self) -> usize {
236	        self.len()
237	    }
238	}
239	
240	#[cfg(feature = "async")]
241	impl<T: Send> KernelSliceArgMut for cuda_async::device_box::DeviceBox<[T]> {}
242	
243	#[cfg(feature = "async")]
244	impl<B> KernelSliceArg for Arc<B>
245	where
246	    B: KernelSliceArg + ?Sized,
247	{
248	    type Elem = B::Elem;
249	
250	    fn cu_deviceptr(&self) -> cuda_core::sys::CUdeviceptr {
251	        self.as_ref().cu_deviceptr()
252	    }
253	
254	    fn len(&self) -> usize {
255	        self.as_ref().len()
256	    }
257	}
258	
259	#[doc(hidden)]
260	#[cfg(feature = "async")]
261	pub fn new_async_kernel_launch<'a>(
262	    func: cuda_core::CudaFunction,
263	    config: cuda_core::LaunchConfig,
264	) -> cuda_async::launch::AsyncKernelLaunch<'a> {
265	    let mut launch = cuda_async::launch::AsyncKernelLaunch::new(Arc::new(func));
266	    launch.set_launch_config(config);
267	    launch
268	}
269	
270	#[doc(hidden)]
271	#[cfg(feature = "async")]
272	pub fn new_owned_async_kernel_launch<R: Send>(
273	    launch: cuda_async::launch::AsyncKernelLaunch<'static>,
274	    resources: R,
275	) -> cuda_async::launch::OwnedAsyncKernelLaunch<R> {
276	    cuda_async::launch::OwnedAsyncKernelLaunch::new(launch, resources)
277	}
278	
279	#[doc(hidden)]
280	#[cfg(feature = "async")]
281	pub fn set_async_kernel_cluster_dim(
282	    launch: &mut cuda_async::launch::AsyncKernelLaunch<'_>,
283	    cluster_dim: (u32, u32, u32),
284	) {
285	    launch.set_cluster_dim(cluster_dim);
286	}
287	
288	#[doc(hidden)]
289	#[cfg(feature = "async")]
290	pub fn set_async_kernel_cooperative(
291	    launch: &mut cuda_async::launch::AsyncKernelLaunch<'_>,
292	    cooperative: bool,
293	) {
294	    launch.set_cooperative(cooperative);
295	}
296	
297	#[doc(hidden)]
298	#[cfg(feature = "async")]
299	pub fn push_async_kernel_scalar<'a, T: KernelScalar + 'a>(
300	    launch: &mut cuda_async::launch::AsyncKernelLaunch<'a>,
301	    value: T,
302	) {
303	    if std::mem::size_of::<T>() != 0 {
304	        launch.push_scalar_arg(value);
305	    }
306	}
307	
308	#[doc(hidden)]
309	#[cfg(feature = "async")]
310	pub fn push_async_read_only_device_slice<B>(
311	    launch: &mut cuda_async::launch::AsyncKernelLaunch<'_>,
312	    buffer: &B,
313	) where
314	    B: KernelSliceArg + ?Sized,
315	{
316	    launch.push_scalar_arg(buffer.cu_deviceptr());
317	    launch.push_scalar_arg(buffer.len() as u64);
318	}
319	
320	#[doc(hidden)]
321	#[cfg(feature = "async")]
322	pub fn push_async_writable_device_slice<B>(
323	    launch: &mut cuda_async::launch::AsyncKernelLaunch<'_>,
324	    buffer: &mut B,
325	) where
326	    B: KernelSliceArgMut + ?Sized,
327	{
328	    launch.push_scalar_arg(buffer.cu_deviceptr());
329	    launch.push_scalar_arg(buffer.len() as u64);
330	}
331	
332	#[doc(hidden)]
333	#[cfg(feature = "async")]
334	pub fn load_cuda_module_from_async_context<F, R>(
335	    device_id: usize,
336	    f: F,
337	) -> Result<R, cuda_async::error::DeviceError>
338	where
339	    F: FnOnce(&Arc<cuda_core::CudaContext>) -> Result<R, crate::EmbeddedModuleError>,
340	{
341	    cuda_async::device_context::with_cuda_context(device_id, |ctx| f(ctx))?.map_err(|error| {
342	        if let crate::EmbeddedModuleError::Driver(error) = error {
343	            cuda_async::error::DeviceError::Driver(error)
344	        } else {
345	            cuda_async::error::DeviceError::KernelCache(error.to_string())
346	        }
347	    })
348	}
349	
350	/// Async-context counterpart of [`crate::load_kernel_module`].
351	///
352	/// Loads a kernel module by stem name on `device_id`, using the async device
353	/// context map to find the underlying [`cuda_core::CudaContext`].
354	#[cfg(feature = "async")]
355	pub fn load_kernel_module_async(
356	    name: &str,
357	    device_id: usize,
358	) -> Result<Arc<cuda_core::CudaModule>, cuda_async::error::DeviceError> {
359	    cuda_async::device_context::with_cuda_context(device_id, |ctx| {
360	        crate::ltoir::load_kernel_module(ctx, name)
361	            .map_err(|error| cuda_async::error::DeviceError::KernelCache(error.to_string()))
362	    })?
363	}
364	
365	// =============================================================================
366	// Argument Wrapper Types
367	// =============================================================================
368	
369	/// Wrapper for scalar values that need to be passed to kernels.
370	///
371	/// This wrapper exists for documentation purposes and to make the intent clear.
372	/// The macro handles unwrapping these properly.
373	///
374	/// # Example
375	///
376	/// ```ignore
377	/// // SAFETY: args match `scale`'s signature.
378	/// unsafe {
379	///     cuda_launch! {
380	///         kernel: scale,
381	///         // ...
382	///         args: (Scalar(factor), &input_dev, &mut output_dev)
383	///     }
384	/// }
385	/// ```
386	pub struct Scalar<T>(pub T);
387	
388	/// Wrapper indicating a device buffer is read-only in the kernel.
389	///
390	/// # Example
391	///
392	/// ```ignore
393	/// // SAFETY: args match `transform`'s signature.
394	/// unsafe {
395	///     cuda_launch! {
396	///         kernel: transform,
397	///         // ...
398	///         args: (ReadOnly(&input_dev), &mut output_dev)
399	///     }
400	/// }
401	/// ```
402	pub struct ReadOnly<'a, T>(pub &'a T);
403	
404	/// Wrapper indicating a device buffer is write-only in the kernel.
405	///
406	/// This is a hint for future optimizations - currently treated same as mutable.
407	///
408	/// # Example
409	///
410	/// ```ignore
411	/// // SAFETY: args match `generate`'s signature.
412	/// unsafe {
413	///     cuda_launch! {
414	///         kernel: generate,
415	///         // ...
416	///         args: (WriteOnly(&mut output_dev),)
417	///     }
418	/// }
419	/// ```
420	pub struct WriteOnly<'a, T>(pub &'a mut T);
421	
422	// =============================================================================
423	// Length Extraction (for slice kernels)
424	// =============================================================================
425	
426	/// Trait for types that have a length (used to pass ptr+len to kernels).
427	pub trait HasLength {
428	    fn len(&self) -> usize;
429	    fn is_empty(&self) -> bool {
430	        self.len() == 0
431	    }
432	}
433	
434	impl<T> HasLength for cuda_core::DeviceBuffer<T> {
435	    fn len(&self) -> usize {
436	        self.len()
437	    }
438	}
439	
440	// =============================================================================
441	// Tests
442	// =============================================================================
443	
444	#[cfg(test)]
445	mod tests {
446	    use super::*;
447	    use std::ffi::c_void;
448	
449	    // Dummy kernel marker for testing
450	    struct TestKernelMarker;
451	    impl CudaKernel for TestKernelMarker {
452	        const PTX_NAME: &'static str = "test_kernel"; // Original function name
453	    }
454	
455	    #[repr(C)]
456	    #[derive(Clone, Copy, Debug, PartialEq)]
457	    struct TestParams {
458	        scale: f32,
459	        bias: i32,
460	    }
461	
462	    fn assert_kernel_scalar<T: KernelScalar>() {}
463	
464	    #[test]
465	    fn test_ptx_name_lookup() {
466	        assert_eq!(TestKernelMarker::PTX_NAME, "test_kernel");
467	    }
468	
469	    #[test]
470	    fn test_scalar_wrapper() {
471	        let s = Scalar(42i32);
472	        assert_eq!(s.0, 42);
473	    }
474	
475	    #[test]
476	    fn test_kernel_scalar_accepts_copy_argument_kinds() {
477	        assert_kernel_scalar::<f32>();
478	        assert_kernel_scalar::<TestParams>();
479	        assert_kernel_scalar::<*const f32>();
480	        assert_kernel_scalar::<*mut f32>();
481	
482	        let offset = 7u32;
483	        let copy_closure = move |x: u32| x + offset;
484	        fn assert_value_is_kernel_scalar<T: KernelScalar>(_value: T) {}
485	        assert_value_is_kernel_scalar(copy_closure);
486	    }
487	
488	    #[test]
489	    fn test_push_kernel_scalar_records_argument_address() {
490	        let mut args = Vec::new();
491	        let mut params = TestParams {
492	            scale: 1.5,
493	            bias: -2,
494	        };
495	        let expected = &mut params as *mut TestParams as *mut c_void;
496	
497	        push_kernel_scalar(&mut args, &mut params);
498	
499	        assert_eq!(args, vec![expected]);
500	        assert_eq!(unsafe { *(args[0] as *const TestParams) }, params);
501	    }
502	
503	    #[test]
504	    fn test_push_kernel_scalar_accepts_copy_closure() {
505	        let mut args = Vec::new();
506	        let offset = 3u32;
507	        let mut copy_closure = move |x: u32| x + offset;
508	        let expected = &mut copy_closure as *mut _ as *mut c_void;
509	
510	        push_kernel_scalar(&mut args, &mut copy_closure);
511	
512	        assert_eq!(args, vec![expected]);
513	    }
514	
515	    #[test]
516	    fn test_push_kernel_scalar_accepts_raw_pointer() {
517	        let mut args = Vec::new();
518	        let value = 42f32;
519	        let mut ptr = &value as *const f32;
520	
521	        push_kernel_scalar(&mut args, &mut ptr);
522	
523	        assert_eq!(args.len(), 1);
524	        assert_eq!(unsafe { *(args[0] as *const *const f32) }, ptr);
525	    }
526	
527	    #[test]
528	    fn test_push_kernel_device_slice_records_pointer_and_len() {
529	        let mut args = Vec::new();
530	        let mut ptr: cuda_core::sys::CUdeviceptr = 0xfeed_beefu64;
531	        let mut len = 1024u64;
532	
533	        push_kernel_device_slice(&mut args, &mut ptr, &mut len);
534	
535	        assert_eq!(args.len(), 2);
536	        assert_eq!(
537	            unsafe { *(args[0] as *const cuda_core::sys::CUdeviceptr) },
538	            ptr
539	        );
540	        assert_eq!(unsafe { *(args[1] as *const u64) }, len);
541	    }
542	}
