 * SPDX-License-Identifier: Apache-2.0
 */

//! Kernel launch infrastructure with rust-analyzer type hint support.
//!
//! This module provides traits and helpers for launching CUDA kernels with
//! full IDE type checking. The key insight is separating concerns:
//!
//! - **Macro** (`cuda_launch!`): Captures kernel identifier → PTX name string,
//!   marshals arguments into a `Vec<*mut c_void>`, and calls
//!   `cuda_core::launch_kernel` directly. The macro is caller-unsafe: it
//!   cannot check argument count or types against the kernel, so every use
//!   must sit inside an `unsafe { }` block. Prefer `#[cuda_module]` for
//!   kernels embedded in your own crate.
//! - **Traits** (`CudaKernel`, `GenericCudaKernel`): Provide PTX entry-point
//!   names for rust-analyzer and compile-time validation.

use std::ffi::c_void;
#[cfg(feature = "async")]
use std::sync::Arc;

// =============================================================================
// Core Traits
// =============================================================================

/// Trait implemented by kernel functions.
///
/// This trait is automatically generated by the `#[kernel]` attribute macro.
/// It provides the PTX entry point name for runtime kernel lookup.
///
/// # Example
///
/// When you write:
/// ```ignore
/// #[kernel]
/// pub fn vecadd(a: &[f32], b: &[f32], mut c: DisjointSlice<f32>) { ... }
/// ```
///
/// The macro generates (on host side only):
/// ```ignore
/// pub struct __vecadd_CudaKernel;
/// impl CudaKernel for __vecadd_CudaKernel {
///     const PTX_NAME: &'static str = "vecadd";  // Original function name
/// }
/// ```
///
/// Note: the function is renamed internally to `cuda_oxide_kernel_<hash>_vecadd`
/// for detection by the compiler backend (the prefix is owned by the
/// workspace-internal `reserved-oxide-symbols` crate), but the PTX entry point
/// uses the original name.
pub trait CudaKernel {
    /// The PTX entry point name (e.g., "vecadd" - the original function name)
    const PTX_NAME: &'static str;
}

/// Trait for generic kernel functions.
///
/// Unlike `CudaKernel`, this trait provides a function to get the PTX name
/// because generic kernels have different PTX names for each type/const
/// specialization.
///
/// # Example
///
/// For a generic kernel:
/// ```ignore
/// #[kernel]
/// pub fn scale<T: Copy + Mul<Output = T>>(factor: T, input: &[T], mut out: DisjointSlice<T>) { ... }
/// ```
///
/// Application code asks the generated helper for a concrete specialization:
/// ```ignore
/// let name = scale_ptx_name::<f32>();
/// // "scale_TID_<32 lowercase hex characters>"
/// ```
///
/// `#[kernel]` implements this trait on an internal marker type and exposes
/// the helper above. Application code should use the helper rather than name
/// that marker directly. The helper also retains the requested specialization
/// in device output before it returns the lookup name.
///
/// # PTX Naming Scheme
///
/// Generic kernels are named `<base>_TID_<hex32>`, where `<hex32>` hashes the
/// concrete generated kernel function-item type. That `FnDef` contains the
/// function identity plus every ordered type and const argument. The host uses
/// `cuda_host::type_id_u128_of_val(&kernel_entry::<T, N>)`; the backend hashes
/// `Instance::ty` for the same entry. Both use rustc's region-erasing stable
/// type hash, so lifetimes do not create spurious PTX variants and the name
/// remains fixed-length regardless of generic arity.
///
/// The bound on `ptx_name` is intentionally just whatever the kernel
/// itself declared — typically `Copy` on the value-passed generics. No
/// `'static` is added: the helper `cuda_host::type_id_u128` uses
/// `core::intrinsics::type_id`, which is bound `T: ?Sized` rather than
/// `T: 'static`, so closures that borrow non-`'static` data still go
/// through the typed launch path (just like they did under the legacy
/// `type_name`-based scheme).
pub trait GenericCudaKernel {
    /// Get the PTX entry point name for this specific instantiation.
    ///
    /// Unlike `CudaKernel::PTX_NAME`, this is a function because the name
    /// depends on the concrete type and const specialization.
    fn ptx_name() -> &'static str;
}

// =============================================================================
// Typed Kernel Arguments
// =============================================================================

/// Marker trait for values that may be passed to a CUDA kernel by value.
///
/// `#[cuda_module]` uses this trait for scalar kernel parameters. Any `Copy`
/// value can be used here because cuda-oxide compiles the host and device
/// instantiations from the same Rust type. Prefer `#[repr(C)]` for structs that
/// must also interoperate with CUDA C/C++ code.
pub trait KernelScalar: Copy {}

impl<T: Copy> KernelScalar for T {}

/// Pushes a by-value scalar kernel argument into a CUDA driver argument list.
///
/// The pointed-to value must remain alive until the launch submission call has
/// returned. The generated `#[cuda_module]` launch methods create stack locals
/// for this purpose before calling this helper.
///
/// # Zero-sized values
///
/// `T` is allowed to be zero-sized (e.g. a closure with no captures, a unit
/// struct). When `size_of::<T>() == 0` the backend drops the corresponding
/// `.param` entirely from the kernel's PTX entry point — the CUDA driver
/// reads no bytes for it — so we must also skip the host push to keep the
/// driver's `kernelParams[]` indices aligned with the kernel's declared
/// parameters. The check is a `const`-fold for monomorphized types and
/// disappears in release builds for non-ZSTs.
#[inline]
#[doc(hidden)]
pub fn push_kernel_scalar<T: KernelScalar>(args: &mut Vec<*mut c_void>, value: &mut T) {
    if std::mem::size_of::<T>() == 0 {
        return;
    }
    args.push(value as *mut T as *mut c_void);
}

/// Returns the `(device pointer, element count)` pair used for read-only slice
/// parameters such as `&[T]`.
#[inline]
#[doc(hidden)]
pub fn read_only_device_buffer_arg<T>(
    buffer: &cuda_core::DeviceBuffer<T>,
) -> (cuda_core::sys::CUdeviceptr, u64) {
    (buffer.cu_deviceptr(), buffer.len() as u64)
}

/// Returns the `(device pointer, element count)` pair used for writable slice
/// parameters such as `&mut [T]` and `DisjointSlice<T>`.
#[inline]
#[doc(hidden)]
pub fn writable_device_buffer_arg<T>(
    buffer: &mut cuda_core::DeviceBuffer<T>,
) -> (cuda_core::sys::CUdeviceptr, u64) {
    (buffer.cu_deviceptr(), buffer.len() as u64)
}

/// Pushes a device slice argument pair into a CUDA driver argument list.
///
/// cuda-oxide device slices lower to two kernel parameters: `CUdeviceptr` and
/// `u64` element count. Keeping that encoding here makes the generated
/// `#[cuda_module]` methods target a stable helper instead of open-coding the
/// ABI in every expansion.
#[inline]
#[doc(hidden)]
pub fn push_kernel_device_slice(
    args: &mut Vec<*mut c_void>,
    ptr: &mut cuda_core::sys::CUdeviceptr,
    len: &mut u64,
) {
    args.push(ptr as *mut cuda_core::sys::CUdeviceptr as *mut c_void);
    args.push(len as *mut u64 as *mut c_void);
}

